+#[derive(Debug, Clone)]
+enum InvokePathSegment {
+    Field(String),
+    Index(usize),
+}
+
+#[derive(Debug)]
+struct PreparedInvokeInput {
+    payload: Value,
+    primary_source: &'static str,
+    sources: Vec<Value>,
+    binding_count: usize,
+    warnings: Vec<String>,
+}
+
+#[derive(Debug)]
+struct InvokeInputError {
+    error_type: &'static str,
+    message: String,
+    next_actions: Vec<String>,
